import { type CreateTask, type TogglePriority } from 'wasp/server/actions'
import { HttpError } from 'wasp/server'

type CreateTaskArgs = {
  description: string
}

export const createTask: CreateTask<CreateTaskArgs, any> = async (args, context) => {
  return context.entities.Task.create({
    data: {
      description: args.description,
    }
  })
}

type TogglePriorityArgs = {
  id: number
}

export const togglePriority: TogglePriority<TogglePriorityArgs, any> = async (args, context) => {
  const task = await context.entities.Task.findUnique({
    where: { id: args.id }
  })
  if (!task) {
    throw new HttpError(404, 'Task not found')
  }

  const newPriority = task.priority === 'High' ? 'Low' : 'High'

  return context.entities.Task.update({
    where: { id: args.id },
    data: { priority: newPriority }
  })
}

