import { useQuery, getTasks, useAction, createTask, togglePriority } from 'wasp/client/operations'
import { useState } from 'react'
import "./Main.css";

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskAction = useAction(createTask)
  const togglePriorityAction = useAction(togglePriority)
  const [description, setDescription] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!description) return
    try {
      await createTaskAction({ description })
      setDescription('')
    } catch (err: any) {
      window.alert('Error creating task: ' + err.message)
    }
  }

  const handleTogglePriority = async (id: number) => {
    try {
      await togglePriorityAction({ id })
    } catch (err: any) {
      window.alert('Error toggling priority: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error.message

  return (
    <main className="container">
      <h2 className="title">Task Priority Application</h2>

      <form onSubmit={handleCreateTask} style={{ marginBottom: '20px' }}>
        <input
          type="text"
          placeholder="New Task Description"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          style={{ marginRight: '10px', padding: '5px' }}
        />
        <button type="submit" className="button button-filled">Add Task</button>
      </form>

      <ul style={{ listStyle: 'none', padding: 0 }}>
        {tasks?.map((task: any) => (
          <li key={task.id} style={{ marginBottom: '10px', border: '1px solid #ccc', padding: '10px', borderRadius: '5px' }}>
            <span style={{ marginRight: '20px' }}>{task.description}</span>
            <span style={{ marginRight: '20px', fontWeight: 'bold' }}>Priority: {task.priority}</span>
            <button
              onClick={() => handleTogglePriority(task.id)}
              className="button button-outlined"
            >
              Toggle Priority
            </button>
          </li>
        ))}
      </ul>
    </main>
  );
}

